Here is a complete implementation of the Naive Bayes classification algorithm for binary text classification in Python using only basic libraries like `math` and `numpy`. The implementation includes preprocessing steps such as tokenization, removal of stop words, and stemming, as well as training, prediction, and evaluation functionalities.

---

### Implementation

```python
import math
import numpy as np
from collections import defaultdict

# Preprocessing functions
def tokenize(text):
    return text.lower().split()

def remove_stopwords(tokens, stopwords):
    return [token for token in tokens if token not in stopwords]

def stem(tokens):
    # Simple stemming by removing suffixes
    return [token[:-2] if len(token) > 2 else token for token in tokens]

def preprocess(text, stopwords):
    tokens = tokenize(text)
    tokens = remove_stopwords(tokens, stopwords)
    tokens = stem(tokens)
    return tokens

# Naive Bayes class
class NaiveBayes:
    def __init__(self, stopwords):
        self.stopwords = stopwords
        self.class_counts = defaultdict(int)
        self.word_counts = defaultdict(lambda: defaultdict(int))
        self.vocab = set()
        self.class_prob = {}
        self.word_prob = defaultdict(lambda: defaultdict(float))

    def train(self, corpus, labels):
        for text, label in zip(corpus, labels):
            tokens = preprocess(text, self.stopwords)
            self.class_counts[label] += 1
            for token in tokens:
                self.word_counts[label][token] += 1
                self.vocab.add(token)

        # Calculate class probabilities
        total_documents = len(labels)
        for label in self.class_counts:
            self.class_prob[label] = self.class_counts[label] / total_documents

        # Calculate word probabilities with Laplace smoothing
        for label in self.word_counts:
            total_words = sum(self.word_counts[label].values())
            for word in self.vocab:
                self.word_prob[label][word] = (self.word_counts[label].get(word, 0) + 1) / (total_words + len(self.vocab))

    def predict(self, text):
        tokens = preprocess(text, self.stopwords)
        log_prob = {}
        for label in self.class_prob:
            log_prob[label] = math.log(self.class_prob[label])
            for token in tokens:
                log_prob[label] += math.log(self.word_prob[label].get(token, 1e-10))
        return max(log_prob, key=log_prob.get)
